SELECT qs.id, qs.name, qs.description, qs.category, qs.user_id, qs.create_time, qs.update_time, qs.is_public, qs.publisher_id, qs.publish_time, qs.source_public_set_id, COALESCE(v.like_count, 0) AS like_count, COALESCE(v.dislike_count, 0) AS dislike_count, COALESCE(imp.import_count, 0) AS import_count FROM question_set qs LEFT JOIN ( SELECT source_public_set_id AS public_set_id, COUNT(1) AS import_count FROM question_set WHERE source_public_set_id IS NOT NULL GROUP BY source_public_set_id ) imp ON imp.public_set_id = qs.id LEFT JOIN ( SELECT question_set_id, SUM(CASE WHEN vote_type = 1 THEN 1 ELSE 0 END) AS like_count, SUM(CASE WHEN vote_type = -1 THEN 1 ELSE 0 END) AS dislike_count FROM question_set_vote GROUP BY question_set_id ) v ON v.question_set_id = qs.id WHERE qs.user_id = #{userId}
AND qs.category = #{category}
AND qs.name LIKE #{name}
ORDER BY qs.create_time DESC

